from google.cloud import storage
from google.cloud import firestore
from google.pubsub import PublisherClient
import os

def handle_storage_event(event, context):
    bucket_name = event['resource']['bucketName']
    blob_name = event['resource']['name']

    # Initialize Firestore and Pub/Sub clients
    firestore_client = firestore.Client()
    pubsub_client = PublisherClient()

    # Get a reference to the bucket and the file in the bucket
    storage_client = storage.Client()
    bucket = storage_client.get_bucket(bucket_name)
    blob = bucket.blob(blob_name)

    # Read the content of the file
    data = blob.download_as_string()

    # Write to Firestore
    doc_ref = firestore_client.collection('data').document()
    doc_ref.set({'file': blob_name, 'content': data})

    # Publish to Pub/Sub
    topic_path = pubsub_client.topic_path('your-project-id', 'your-pubsub-topic')
    pubsub_client.publish(topic_path, data)